sys_script_fix.script:
(function() {
    var patientID = 'PAT0001010';
    var patientGR = new GlideRecord('u_patient_record');
    patientGR.addQuery('u_number', patientID);
    patientGR.query();

    if (patientGR.next()) {
        var patientSysId = patientGR.getUniqueValue();

        var labTT = new GlideRecord('u_lab_test');
        labTT.addQuery('u_patient', patientSysId);
        labTT.query();

        if (!labTT.hasNext()) {
            gs.print('No lab tests for this patient.');
        } else {
            while (labTT.next()) {
                gs.print('Lab Test: ' + labTT.u_test_results);
            }
        }
    } else {
        gs.print('Patient not found with ID: ' + patientID);
    }
})();
